import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import axios from "axios";
import Api from "../api/Api";

function Admin() {
  const [users, setUsers] = useState([]);
  const [scheduleMap, setScheduleMap] = useState({});
  const [editingSchedule, setEditingSchedule] = useState({});
  const [showRequests, setShowRequests] = useState(false);
  const [statusFilter, setStatusFilter] = useState("All");
  const [requests, setRequests] = useState([]);
  const [orderMap, setOrderMap] = useState({});
  const [isSorted, setIsSorted] = useState(false);


  const [locations, setLocations] = useState([]);
const [supervisors, setSupervisors] = useState([]);

const [selectedSupervisor, setSelectedSupervisor] =
  useState("");

const [selectedLocations, setSelectedLocations] =
  useState([]);
  // ================= USERS =================
  const fetchUsers = async () => {
    try {
      const res = await axios.get(Api.get_All_User);
      setUsers(res.data || []);

const onlySupervisors =
  res.data.filter(
    (u) => u.role === "supervisor"
  );

setSupervisors(onlySupervisors);
    } catch (err) {
      console.log(err);
    }
  };



  const fetchLocations = async () => {
  try {
    const res = await axios.get(
      Api.get_All_Locations
    );

    setLocations(res.data);

  } catch (err) {
    console.log(err);
  }
};
  // ================= REQUESTS =================
  const fetchRequests = async () => {
    try {
      const res = await axios.get(Api.get_All_Emg_Req);

      console.log("RAW RESPONSE:", res.data);

      const data =
        res.data?.data ||
        res.data?.requests ||
        res.data ||
        [];

      setRequests(Array.isArray(data) ? data : []);
    } catch (err) {
      console.log("FETCH ERROR:", err);
      setRequests([]);
    }
  };
useEffect(() => {
  fetchUsers();
  fetchLocations();
}, []);



const assignLocations = async () => {
  try {

    await axios.put(
      Api.assign_Supervisor,
      {
        supervisorId:
          selectedSupervisor,

        locationIds:
          selectedLocations,
      }
    );

    alert("Locations Assigned");

  } catch (err) {
    console.log(err);
  }
};

  // ================= ASSIGN ORDER (LIVE UI UPDATE) =================
  const handleAssignOrder = async (id) => {
    try {
      const order = orderMap[id];

      if (order === undefined || order === "") {
        return alert("Enter order first");
      }

      const numOrder = Number(order);

      // 🔥 UI UPDATE FIRST
      setRequests((prev) =>
        prev.map((req) =>
          req._id === id
            ? { ...req, scheduleOrder: numOrder }
            : req
        )
      );

      // 🔥 API CALL (CORRECT)
      const res = await axios.put(
        `${Api.update_Emg_Order}/${id}`,
        {
          scheduleOrder: numOrder,
        }
      );

      console.log("UPDATE RESPONSE:", res.data);

      setOrderMap({});
      setIsSorted(false);

    } catch (err) {
      console.log("ASSIGN ERROR:", err.response || err);
      alert("Assign failed");
    }
  };

  // ================= UPDATE ORDER =================
  const handleUpdateAssign = async (id) => {
    try {
      const order = orderMap[id];

      if (!order && order !== 0) {
        return alert("Enter order first");
      }

      setRequests((prev) =>
        prev.map((req) =>
          req._id === id
            ? { ...req, scheduleOrder: Number(order) }
            : req
        )
      );

      await axios.put(
        `${Api.update_Emg_Order}/${id}`,
        {
          scheduleOrder: Number(order),
        }
      );

      setOrderMap({});
      setIsSorted(false);

    } catch (err) {
      console.log(err);
    }
  };

  // ================= FINAL SORT =================
  const filteredRequests = requests.filter((req) => {
    if (statusFilter === "All") {
      return req.status !== "Completed";
    }

    return req.status === statusFilter;
  });

  const displayedRequests = isSorted
    ? [...filteredRequests].sort(
      (a, b) =>
        (a.scheduleOrder || 0) -
        (b.scheduleOrder || 0)
    )
    : filteredRequests;



  const handleSchedule = async (id) => {
    try {
      const data = scheduleMap[id];

      if (!data?.date || !data?.time) {
        return alert("Select Date & Time");
      }

      await axios.put(`${Api.update_Emg_Order}/${id}`, {
        scheduledDate: data.date,
        scheduledTime: data.time,
        status: "Scheduled",
      });

      setRequests((prev) =>
        prev.map((req) =>
          req._id === id
            ? {
              ...req,
              scheduledDate: data.date,
              scheduledTime: data.time,
              status: "Scheduled",
            }
            : req
        )
      );

      setEditingSchedule((prev) => ({
        ...prev,
        [id]: false,
      }));

      setScheduleMap((prev) => ({
        ...prev,
        [id]: {},
      }));

      alert("Schedule Updated Successfully");
    } catch (error) {
      console.log(error);
      alert("Schedule Failed");
    }
  };


  return (
    <div className="min-h-screen bg-[#4CBB17]/20">

      <div >

        {/* HEADER */}
        {/* HEADER */}
        <div className="mb-8 bg-[#4CBB17]/40 px-6 ">
          <div className="flex items-center justify-between">

            {/* Logo + Title */}
            <div >
              <h1 className="flex items-center gap-3 text-5xl font-extrabold text-green-900">
                <img
                  src="garbageVehicle.jpeg"
                  alt=""
                  className="w-16 h-16 object-contain"
                />
                CleanTrack
              </h1>

              <p className="text-gray-900 p-2">
                Smart Waste Management Control Center
              </p>
            </div>

            {/* Navigation Links */}
            <div className="flex items-center gap-8 text-lg font-semibold">

              <Link
                to="/create-account"
                className="text-green-900 hover:text-white-900 transition-all duration-300 hover:scale-105"
              >
                Create User
              </Link>

              <button
                onClick={() => {
                  setShowRequests(!showRequests);
                  fetchRequests();
                }}
                className="text-green-900 hover:text-green-900 transition-all duration-300 hover:scale-105"
              >
                View Requests
              </button>

              <Link
  to="/create-location"
  className="text-green-900 hover:scale-105 transition"
>
  Create Locations
</Link>

             <Link
  to="/assign-location"
  className="text-green-900 hover:scale-105 transition"
>
  Assign Location
</Link>


            </div>
          </div>
        </div>

        <div className="text-center mb-10">
        <h1 className="text-5xl font-extrabold text-black-900">
          Admin Dashboard
        </h1>
      </div>

        {/* USERS */}
        <div className="bg-white rounded-2xl shadow-sm border border-[#d6ddd2] p-6 mb-8 m-8">

          <div className="flex justify-between items-center mb-6">

            <h2 className="text-2xl font-bold text-green-900">
              User Management
            </h2>

            <span className="bg-green-100 text-green-800 px-4 py-2 rounded-full text-sm font-semibold">
              {users.length} Users
            </span>

          </div>

          <div className="overflow-x-auto">

            <table className="w-full">

              <thead>
                <tr className="bg-green-900 text-white">
                  <th className="p-4 text-left">Name</th>
                  <th className="p-4 text-left">Mobile</th>
                  <th className="p-4 text-left">Role</th>
                </tr>
              </thead>

              <tbody>
                {users.map((user) => (
                  <tr
                    key={user._id}
                    className="border-b hover:bg-green-50 transition"
                  >
                    <td className="p-4 font-medium">
                      {user.name}
                    </td>

                    <td className="p-4">
                      {user.mobile}
                    </td>

                    <td className="p-4">
                      <span className="bg-green-100 text-green-800 px-3 py-1 rounded-full text-sm font-medium">
                        {user.role}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>

            </table>

          </div>

        </div>




        {/* REQUESTS */}
        {showRequests && (
          <div>

            <div className="flex justify-between items-center mb-6 m-8">

              <div>
                <h2 className="text-3xl font-bold text-green-900">
                  Active Requests
                </h2>

                <p className="text-gray-500 text-sm">
                  Pickup Scheduling & Monitoring
                </p>
              </div>

              <div className="flex items-center gap-3">

                <select
                  value={statusFilter}
                  onChange={(e) =>
                    setStatusFilter(e.target.value)
                  }
                  className="border border-gray-300 rounded-lg px-4 py-2 bg-white"
                >
                  <option value="All">All Active</option>
                  <option value="Pending">Pending</option>
                  <option value="Scheduled">Scheduled</option>
                  <option value="Arrived">Arrived</option>
                  <option value="Completed">Completed</option>
                </select>

                <div className="bg-white border border-[#d6ddd2] px-5 py-3 rounded-xl">
                  <span className="font-semibold">
                    Total Requests:
                  </span>{" "}
                  {displayedRequests.length}
                </div>

              </div>

            </div>

            {displayedRequests.length === 0 ? (

              <div className="bg-white rounded-2xl shadow-sm border border-[#d6ddd2] p-10 text-center">
                No requests found
              </div>

            ) : (

              <div className="grid lg:grid-cols-2 xl:grid-cols-4 gap-6">

        {["High", "Medium", "Low"].map((priority) => {
  const priorityRequests = displayedRequests.filter(
    (req) => req.priority === priority
  );

  if (priorityRequests.length === 0) return null;

  return (
    <div key={priority} className="mb-10">
      <h2
        className={`text-2xl font-bold mb-4 ${
          priority === "High"
            ? "text-red-600"
            : priority === "Medium"
            ? "text-yellow-600"
            : "text-green-600"
        }`}
      >
        {priority === "High"
          ? "🔴 High Priority Tasks"
          : priority === "Medium"
          ? "🟡 Medium Priority Tasks"
          : "🟢 Low Priority Tasks"}
      </h2>

      <div className="grid lg:grid-cols-2 xl:grid-cols-4 gap-6">
        {priorityRequests.map((req) => (
          <div
            key={req._id}
            className="bg-white rounded-2xl border border-[#d6ddd2] p-6 hover:shadow-lg transition"
          >
            {/* Your existing request card code here */}
          </div>
        ))}
      </div>
    </div>
  );
})}

              </div>

            )}

          </div>
        )}

      </div>

    </div>
  );
}

export default Admin
